1	export type Request = {
2	  jsonrpc: '2.0'
3	  method: string
4	  params?: any
5	  id: number
6	}
7	
8	export type Response = SuccessResponse | ErrorResponse
9	
10	export type SuccessResponse = {
11	  jsonrpc: '2.0'
12	  result: any
13	  id: number
14	}
15	
16	export type ErrorResponse = {
17	  jsonrpc: '2.0'
18	  error: {
19	    code: number
20	    message: string
21	    data: any
22	  }
23	  id: number
24	}
25	
26	export function isErrorResponse(response: Response): response is ErrorResponse {
27	  return (response as ErrorResponse).error !== undefined
28	}
