import type { DMMF } from '@prisma/dmmf'

import { mapScalarType } from './type-map'

/** Generates a TypeScript interface for a Prisma model. */
export function emitInterface(model: DMMF.Model, allModelNames: Set<string>, allEnumNames: Set<string>): string {
  const lines: string[] = []
  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (field.kind === 'unsupported') continue

    let tsType: string
    if (field.kind === 'scalar') {
      tsType = mapScalarType(field.type)
    } else if (field.kind === 'enum') {
      tsType = field.type
    } else {
      // Relation field — use the related model's name
      tsType = field.type
    }

    if (field.isList) {
      tsType = `${tsType}[]`
    }

    if (field.kind === 'object') {
      // Relations are optional in REST responses
      const nullable = !field.isRequired ? ` | null` : ''
      lines.push(`  ${field.name}?: ${tsType}${nullable}`)
    } else {
      const nullable = !field.isRequired ? ' | null' : ''
      lines.push(`  ${field.name}: ${tsType}${nullable}`)
    }
  }

  lines.push('}')
  return lines.join('\n')
}

