import type { DMMF } from '@prisma/dmmf'

import { mapScalarType } from './type-map'

interface IdField {
  name: string
  tsType: string
}

function getIdFields(model: DMMF.Model): IdField[] {
  // Single @id field
  const singleId = model.fields.filter((f) => f.isId)
  if (singleId.length > 0) {
    return singleId.map((f) => ({ name: f.name, tsType: mapScalarType(f.type) }))
  }

  // Compound @@id
  if (model.primaryKey) {
    return model.primaryKey.fields.map((fieldName) => {
      const field = model.fields.find((f) => f.name === fieldName)
      return { name: fieldName, tsType: field ? mapScalarType(field.type) : 'unknown' }
    })
  }

  return []
}

function getOmittedFieldNames(model: DMMF.Model, idFields: IdField[]): string[] {
  const omitted: string[] = []

  // Omit auto-generated ID fields from create data
  for (const idField of idFields) {
    const field = model.fields.find((f) => f.name === idField.name)
    if (field?.hasDefaultValue) {
      omitted.push(field.name)
    }
  }

  // Omit relation fields — they are managed through foreign key scalars
  for (const field of model.fields) {
    if (field.kind === 'object') {
      omitted.push(field.name)
    }
  }

  return omitted
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/** Generates a typed CRUD client class for a single Prisma model. */
export function emitModelClient(model: DMMF.Model): string {
  const idFields = getIdFields(model)
  const modelName = model.name
  const endpoint = `/${camelCase(modelName)}`
  const className = `${modelName}Client`
  const omitted = getOmittedFieldNames(model, idFields)

  const lines: string[] = []
  lines.push(`export class ${className} {`)
  lines.push(`  #baseUrl: string`)
  lines.push('')
  lines.push(`  constructor(baseUrl: string) {`)
  lines.push(`    this.#baseUrl = baseUrl`)
  lines.push(`  }`)

  // findMany
  lines.push('')
  lines.push(`  async findMany(params?: { skip?: number; take?: number }): Promise<${modelName}[]> {`)
  lines.push(`    const query = new URLSearchParams()`)
  lines.push(`    if (params?.skip !== undefined) query.set('skip', String(params.skip))`)
  lines.push(`    if (params?.take !== undefined) query.set('take', String(params.take))`)
  lines.push(`    const qs = query.toString()`)
  lines.push(`    const url = \`\${this.#baseUrl}${endpoint}\${qs ? \`?\${qs}\` : ''}\``)
  lines.push(`    const res = await fetch(url)`)
  lines.push(`    if (!res.ok) throw new Error(\`GET ${endpoint} failed: \${res.status}\`)`)
  lines.push(`    return res.json() as Promise<${modelName}[]>`)
  lines.push(`  }`)

  if (idFields.length > 0) {
    const whereType = `{ ${idFields.map((f) => `${f.name}: ${f.tsType}`).join('; ')} }`
    const urlPath = idFields.map((f) => `\${where.${f.name}}`).join('/')

    // findUnique
    lines.push('')
    lines.push(`  async findUnique(where: ${whereType}): Promise<${modelName} | null> {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}${endpoint}/${urlPath}\`)`)
    lines.push(`    if (res.status === 404) return null`)
    lines.push(`    if (!res.ok) throw new Error(\`GET ${endpoint}/${urlPath} failed: \${res.status}\`)`)
    lines.push(`    return res.json() as Promise<${modelName}>`)
    lines.push(`  }`)

    // create
    const omitUnion = omitted.length > 0 ? omitted.map((n) => `'${n}'`).join(' | ') : null
    const createType = omitUnion ? `Omit<${modelName}, ${omitUnion}>` : modelName
    lines.push('')
    lines.push(`  async create(data: ${createType}): Promise<${modelName}> {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}${endpoint}\`, {`)
    lines.push(`      method: 'POST',`)
    lines.push(`      headers: { 'Content-Type': 'application/json' },`)
    lines.push(`      body: JSON.stringify(data),`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`POST ${endpoint} failed: \${res.status}\`)`)
    lines.push(`    return res.json() as Promise<${modelName}>`)
    lines.push(`  }`)

    // update
    const allIdNames = idFields.map((f) => `'${f.name}'`).join(' | ')
    const updateOmitUnion = omitted.length > 0 ? [...new Set([...idFields.map((f) => f.name), ...omitted])].map((n) => `'${n}'`).join(' | ') : allIdNames
    lines.push('')
    lines.push(`  async update(where: ${whereType}, data: Partial<Omit<${modelName}, ${updateOmitUnion}>>): Promise<${modelName}> {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}${endpoint}/${urlPath}\`, {`)
    lines.push(`      method: 'PATCH',`)
    lines.push(`      headers: { 'Content-Type': 'application/json' },`)
    lines.push(`      body: JSON.stringify(data),`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`PATCH ${endpoint}/${urlPath} failed: \${res.status}\`)`)
    lines.push(`    return res.json() as Promise<${modelName}>`)
    lines.push(`  }`)

    // delete
    lines.push('')
    lines.push(`  async delete(where: ${whereType}): Promise<${modelName}> {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}${endpoint}/${urlPath}\`, { method: 'DELETE' })`)
    lines.push(`    if (!res.ok) throw new Error(\`DELETE ${endpoint}/${urlPath} failed: \${res.status}\`)`)
    lines.push(`    return res.json() as Promise<${modelName}>`)
    lines.push(`  }`)
  }

  lines.push('}')
  return lines.join('\n')
}

