function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: overrides.type,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

const modelNames = new Set(['User', 'Post'])
const enumNames = new Set(['Role'])

describe('emitInterface', () => {
  test('generates interface with scalar fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String' }),
      makeField({ name: 'age', type: 'Int' }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        email: string
        age: number
      }"
    `)
  })

  test('handles optional fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        name: string | null
      }"
    `)
  })

  test('handles list fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'tags', type: 'String', isList: true }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        tags: string[]
      }"
    `)
  })

  test('handles enum fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        role: Role
      }"
    `)
  })

  test('handles relation fields as optional', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true }),
      makeField({ name: 'profile', type: 'Profile', kind: 'object', isRequired: false }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        posts?: Post[]
        profile?: Profile | null
      }"
    `)
  })

  test('skips unsupported fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'legacy', type: 'circle', kind: 'unsupported' }),
      makeField({ name: 'email', type: 'String' }),
    ])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        email: string
      }"
    `)
  })

  test('handles model with no fields', () => {
    const model = makeModel('Empty', [])
    expect(emitInterface(model, modelNames, enumNames)).toMatchInlineSnapshot(`
      "export interface Empty {
      }"
    `)
  })
})

