import type { DMMF } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { emitModelClient } from '../emit-crud-client'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: overrides.type,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[], primaryKey?: DMMF.PrimaryKey | null): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: primaryKey ?? null,
  }
}

describe('emitModelClient', () => {
  test('generates CRUD client for model with single @id', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'email', type: 'String', isUnique: true }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = emitModelClient(model)
    expect(result).toContain('export class UserClient')
    expect(result).toContain('async findMany')
    expect(result).toContain('async findUnique(where: { id: number })')
    expect(result).toContain("async create(data: Omit<User, 'id'>)")
    expect(result).toContain("async update(where: { id: number }, data: Partial<Omit<User, 'id'>>)")
    expect(result).toContain('async delete(where: { id: number })')
    expect(result).toContain('#baseUrl')
  })

  test('generates CRUD client for model with compound @@id', () => {
    const model = makeModel(
      'PostTag',
      [
        makeField({ name: 'postId', type: 'Int' }),
        makeField({ name: 'tagId', type: 'Int' }),
        makeField({ name: 'assignedAt', type: 'DateTime' }),
      ],
      { name: 'postId_tagId', fields: ['postId', 'tagId'] },
    )
    const result = emitModelClient(model)
    expect(result).toContain('async findUnique(where: { postId: number; tagId: number })')
    expect(result).toContain('${where.postId}/${where.tagId}')
  })

  test('omits relation fields from create/update types', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
      makeField({ name: 'author', type: 'User', kind: 'object' }),
      makeField({ name: 'authorId', type: 'Int' }),
    ])
    const result = emitModelClient(model)
    expect(result).toContain("Omit<Post, 'id' | 'author'>")
  })

  test('generates only findMany for model with no ID', () => {
    const model = makeModel('Log', [
      makeField({ name: 'message', type: 'String' }),
      makeField({ name: 'level', type: 'String' }),
    ])
    const result = emitModelClient(model)
    expect(result).toContain('async findMany')
    expect(result).not.toContain('async findUnique')
    expect(result).not.toContain('async create')
    expect(result).not.toContain('async update')
    expect(result).not.toContain('async delete')
  })

  test('keeps non-default ID in create type', () => {
    const model = makeModel('Config', [
      makeField({ name: 'key', type: 'String', isId: true, hasDefaultValue: false }),
      makeField({ name: 'value', type: 'String' }),
    ])
    const result = emitModelClient(model)
    // key has no default, so it should not be omitted from create
    expect(result).toContain('async create(data: Config)')
  })
})

