  test('writes rest-client.ts to the output directory', async () => {
    const outputDir = path.join(tmpDir, 'generated')
    await onGenerate(stubOptions(outputDir))

    const filePath = path.join(outputDir, 'rest-client.ts')
    const content = await fs.readFile(filePath, 'utf-8')

    expect(content).toContain('// Generated by prisma-generator-rest-client')
    expect(content).toContain("export type Role = 'ADMIN' | 'USER'")
    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface Post {')
