    expect(content).toContain('export class PostClient {')
    expect(content).toContain('export class RestClient {')
    expect(content).toContain('readonly user: UserClient')
    expect(content).toContain('readonly post: PostClient')
  })

  test('creates the output directory if it does not exist', async () => {
    const outputDir = path.join(tmpDir, 'deep', 'nested', 'dir')
    await onGenerate(stubOptions(outputDir))

    const stat = await fs.stat(outputDir)
    expect(stat.isDirectory()).toBe(true)
  })

  test('generates correct interface for User model', async () => {
    const outputDir = path.join(tmpDir, 'generated')
    await onGenerate(stubOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    // User interface should have optional relation and nullable name
    expect(content).toContain('name: string | null')
    expect(content).toContain('role: Role')
    expect(content).toContain('posts?: Post[]')
  })

  test('generates correct CRUD operations', async () => {
    const outputDir = path.join(tmpDir, 'generated')
    await onGenerate(stubOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    // Auto-incremented IDs should be omitted from create
    expect(content).toContain("Omit<User, 'id' | 'posts'>")
    expect(content).toContain("Omit<Post, 'id' | 'author'>")
  })
})

